
import React, { useState, useEffect } from "react";


import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt, CheckBoxSlide_Cmpt, TextAreaHRM_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys,  compareJSON, fetchEncryptStream, _monthNames, qryKClient } from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import {  generateI589 } from "../services/print_service";
import { getMainApplicantInfo } from "../services/customer_fetch_service";



const TextInput = TextInput_Cmpt();






const CheckBoxSlide = CheckBoxSlide_Cmpt();


const TextAreaHRM = TextAreaHRM_Cmpt();












