const GenerateI598  = ({ data,  confirm }) => {
	
	
const frmNm = "data_frm_i598"


let flds = [
	"someone_help_preparing", 
	"family_help_preparing", 
	"counsel_provider_list",



	"political_AB", 
	"political_BB",
	"political_2B",  
	"political_4B"
]



	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);


	const loadDoc  = async ()  => {
		let bdyq2 = {
			query: "getScanDocumentsNotary",
			params: {
				":customerId" : getStore(qryKClient()).clientNotaryId,
				":documentType": "uscis_i598"
			},
			queryString: "customerId contain :customerId AND documentType contain :documentType",
		};

		const res = fetchEncryptStream(bdyq2);
		const td = await res;

		if (td && !td.error) {

				let docId = ObjectKeys(td)[0];

				if(td[docId]){
					updStore(frmNm, td[docId]);
					updStore(frmNm + "_bck", JSON.parse(JSON.stringify(td[docId])));
					set_obs(gen16CodeId())
				}
				else{
					updStore(frmNm, null);
					set_obs(gen16CodeId())
				}
			
		}

	}


	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			updStore(frmNm, null);
			set_obs(gen16CodeId());

			setTimeout(() => {
				loadDoc();
				let user = {...getStore(qryKClient())};
				let frm_userInfo = {
					"dob":	user?.dob,
					"dateOfBirth": user?.dateOfBirth,
					"name":user?.firstName ? `${user?.firstName} ${user?.middleName?user?.middleName+" ":""}${user?.lastName} ` :"",
					"ss": user?.ss
				};
			
				updStore(frmNm+"_userInfo", frm_userInfo);
				set_obs(gen16CodeId())
			}, 50);
			return () => {
				updStore(frmNm, null);
			}; 
		}
	});

	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};



	const save  = async ()  => {

		let ffm =  getStore(frmNm);

		let bdyq2 = {};
		if(ffm["documentNotaryId"]){
			let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
		
			bdyq2 = {
				query: "updateDocumentsNotary",
				params:{
					"documentNotaryId": ffm["documentNotaryId"]
				},
				data2update: diff.data
			};
		}
		else{
			ffm["customerId"] = getStore(qryKClient()).clientNotaryId;
			ffm["documentType"] = "uscis_i598";
			ffm["documentNotaryId"] = gen16CodeId();
			bdyq2 = {
				query: "addDocumentsNotary",
				form:ffm
			};
		}

		// * Class B Automovile (Mar 2010), C: Truck over 7500KG (Jun 2014)
	
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && td.data) {
			updStore(frmNm, td.data);
			set_obs(gen16CodeId());
			close();
		}
	}


	const print  = async ()  => {

		let user = {...getStore(qryKClient())};
		let i598_data = getStore(frmNm);
		let uu = Object.assign( {},user, i598_data );
		
		let ffm = {...getMainApplicantInfo(uu)};
		
		let I598 = getStore("print_structure")?.i598_details_struct_print || {};


		let pdfUri = await generateI589(ffm,  I598, true, true);
		window.open(pdfUri);
	}


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	



	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					I-589
				</p>
				<div className="flexSpace"/>
				<div className="card">
						<GrayButton label={"Imprimir"} clickHandler={print}/>
					
				</div>
			</div>
			
			
			

		
			<div className="_dsplFlx spaceAround flxWrp" style={{margin:"30px 0px 0 0"}}>
					
			<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["counsel_provider_list"]}
						keyCode={57}
						updChange={(e)=>updFrm("counsel_provider_list",e)}
					/>
					<span className={`checklabel`}>
						{"Counselor List"}
					</span>
				</div>
				
				<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["family_help_preparing"]}
						keyCode={35}
						updChange={(e)=>updFrm("family_help_preparing",e)}
					/>
					<span className={`checklabel`}>
						{"Family Helping"}
					</span>
				</div>

				<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["someone_help_preparing"]}
						keyCode={39}
						updChange={(e)=>updFrm("someone_help_preparing",e)}
					/>
					<span className={`checklabel`}>
						{"Someone preparing"}
					</span>
				</div>
			</div>
			
			<div className="_dsplFlx spaceAround"  style={{marginTop:20}}> 
			
			</div>
			<div className="_dsplFlx spaceAround flxWrp"> 
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_AB"]} 
					label={"¿Usted, su familia, amigos cercanos o colegas alguna vez han sufrido daños, malos tratos o amenazas en el pasado por parte de alguien?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_AB",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_BB"]} 
					label={"¿Temes daño o maltrato si regresas a tu país de origen?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_BB",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_2B"]} 
					label={"¿Tiene miedo de ser torturado en su país de origen o en cualquier otro país al que pueda ser devuelto?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_2B",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_4B"]} 
					label={"Después de salir del país del que solicita asilo, usted o su cónyuge o hijo(s) que ahora están en los Estados Unidos, ¿viajaron o residieron en algún otro país antes de ingresar a los Estados Unidos?, el nombre de cada país y la duración de la estadía solicitó la condición de refugiado. o para asilo mientras estuvo allí, y si no, por qué él o ella no lo hizo.?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_4B",e)}
				/>

			</div> 
			
			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
				<DateCalComponent  
					init={getStore(frmNm)?.["translateDate"]} 
					label={"Fecha de la traduccion"}
					updDate={(e)=>updFrm("translateDate",e)}
				/>
			</div>

			{validSv?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={save}/>
						
					</div>
				</div>
			):<div className="card"/>}


		</div>
	)

}



export default GenerateI598;








const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}






